#include <stdio.h>
int main() {
    int T, N, i, j, paid, due;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        due = 0;
        paid = 0;
        for (i = 0; i < N; i++) {
            int x;
            scanf("%d", &x);
            if (x == 1) {
                paid++;
            }
        }
        for (i = 0; i < N; i++) {
            int x;
            scanf("%d", &x);
            if (x == 0) {
                due += 1100;
            } else if (paid > 0) {
                paid--;
                due += 100;
            }
        }
        printf("%d\n", due);
    }
    return 0;
}

