public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int due = 0;
            int paid = 0;
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
                if (arr[i] == 1) {
                    paid++;
                }
            }
            for (int i = 0; i < N; i++) {
                if (arr[i] == 0) {
                    due += 1100;
                } else if (paid > 0) {
                    paid--;
                    due += 100;
                }
            }
            System.out.println(due);
        }
    }
}

